var b="url",c="物料标签.html",d="generationDate",e=new Date(1781585052324.45),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="ca2a877801e344fbbe13ff0d3c3d10c8",v="type",w="Axure:Page",x="物料标签",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="ebd2ffcc5a7c4f92ac916e3e011e2696",E="label",F="打印",G="说明",H="<p><span>1.校验空值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.校验字段：物料名称、颜色、规格/门幅</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.存在空时Toast提示：请选择XXX（第Y行）</span></p><p><span>2.校验“标签张数”不为空且大于0，否则Toast提示：请填写&quot;标签张数&quot;</span></p><p><span>3.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#70B603;\">门幅/规格</span><span>处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将编辑域的值作</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#70B603;\">去空格处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.校验填写的“门幅/规格”是否已存在于当前物料中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.若存在，无须处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ii.若不存在，将当前规格/门幅自动添加至物料中；规格编码按3位流水自动生成</span></p><p><span>4.校验是否有相同'物料编码-颜色-规格/门幅'的行，否则Toast提示：SKU重复（行X，Y）</span></p><p><span>5.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#70B603;\">颜色</span><span>处理：校验选中的“门幅/规格”是否已存在于当前物料中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.若存在，无须处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.若不存在，将当前颜色自动添加至物料中；色号跟随选中颜色</span></p><p><span>6.按&quot;标签张数&quot;生成唯一码</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.按照规则依次自动生成</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.唯一码仅绑定对应的物料SKU</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.唯一码为无数量，属于未入库的唯一码</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.可视为库存为0的唯一码(在[库存查询]中无法查到)仅打印</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.直至通过小程序扫码入库后填写数量再正式入库，使其再[库存查询]可查</span></p><p><span>7.按钮处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.Toast提示：操作成功</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.按钮限制点击，防止重复生成唯一码重复打印</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.当前【打印】按钮禁用2S，文本展示为&quot;打印中&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.2s后按钮释放，文本变回“打印”</span></p><p><span>7.打印处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.调用打印机；依次打印唯一码标签</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.标签尺寸：40mm*60mm</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.标签样式见图示，包含信息：唯一码对应二维码、唯一码、物料名称、物料规格、物料颜色、当前打印时间</span></p>",I="2",J="618e454a586a437395e2a7998bd2ca82",K="操作",L="<p><span>新增：</span></p><p><span>1.向下新增一行</span></p><p><span><br></span></p><p><span>移除：</span></p><p><span>1.移除当前行</span></p><p><span>2.仅剩一行时无法移除；至少保留一行</span></p>",M="3",N="ba51fca307f1438994fe7239cc17c545",O="物料编码",P="<p><span>跟随选中物料的“物料编码”</span></p>",Q="4",R="cd08113c1cba4967bfe36a5adffc7f3a",S="物料名称",T="<p><span>1.下拉以字节阵展示“物料编码”和“物料名称”</span></p><p><span>2.支持模糊查询“物料编码”和“物料名称”</span></p><p><span>3.下拉重新选择后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.返回”物料名称“至当前</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.查询选择物料的对应”物料编码“、“单位”至当前行</span></p>",U="5",V="34895373521341fba03b66c5b8d76094",W="单位",X="<p><span>跟随选中物料的“单位”</span></p>",Y="6",Z="585e8096ba74453b8d26b42d27aad67f",ba="颜色",bb="<p><span>1.[基础数据&gt;&gt;物料颜色]中全部“启用”的颜色</span></p><p><span>2.排序：物料编码对应物料下的“颜色”优先，其它物料颜色排在后面</span></p><p><span>3.支持对“物料颜色”的模糊查询</span></p>",bc="7",bd="75f976f215dc4ed4bff132b50096be6c",be="规格/门幅",bf="<p><span>1.点击编辑域，默认下拉该物料中已有的“规格/门幅”，可选中后将结果返回值当前编辑域</span></p><p><span>2.编辑时支持即时模糊搜索该物料中已有的“规格/门幅”</span></p><p><span>3.支持手动编辑</span></p><p><span>4.支持快捷&quot;×&quot;操作清除当前编辑</span></p>",bg="8",bh="b67fc26a89f048fc9c70537baf70ba51",bi="标签张数",bj="<p><span>1.格式：正整数</span></p><p><span>2.新增行时默认为空，无默认值</span></p>",bk="9",bl="4a443818c00b4c61b39d45816e474259",bm="采购单据：",bn="<p><span>1.数据源：状态为“已通过”的采购订单号</span></p><p><span>2.下拉格式：以字节阵展示'采购单号'、'关联单据'、'供应商'这3列</span></p><p><span>3.支持模糊搜索采购订单的'采购单号'或'关联单据'或'供应商'</span></p><p><span>4.选中后仅返回'采购单号'至下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.清空“生产订单”下拉域的值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.拉取“采购单号”的数据至对应的物料清单</span></p>",bo="10",bp="9fc91d9c92ce42b4929d7b8458dba308",bq="生产订单：",br="<p><span>1.数据源：[物料计划&gt;&gt;订单物料需求]中的生产订单号</span></p><p><span>2.下拉格式：以字节阵展示'生产单号'、'自定义单号'、'款号'这3列</span></p><p><span>3.支持模糊搜索生产订单的'生产单号'或'自定义单号'或'款号'</span></p><p><span>4.选中后仅返回'生产单号'至下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.清空“采购单据”下拉域的值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.拉取[物料计划&gt;&gt;订单物料需求]中“生产订单”的对应'订单物料需求'的数据至对应的物料清单</span></p>",bs="11",bt="134aefe51dbb4a1db54d68570fcd971c",bu="保存",bv="<p><span>1.校验是否存在勾选，否则Toast提示：请至少勾选一行</span></p><p><span>2.将勾选行的“物料编码-规格/门幅-颜色”与现有[生成标签]清单中的匹配</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.若已存在，不再重复新增行</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.仅将未存在过的SKU增量补充至清单底部</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.'标签张数'默认为空，不要给默认值</span></p><p><span>3.判断当前'生成标签'的清单下第一行的“物料编码”是否为空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.非空：不做处理；</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.空：自动移除第一行</span></p>",bw="12",bx="33d05bfbf7694b0295635ca0a48a2780",by="滞留标签",bz="<p><span>1.数据源：通过[物料标签&gt;&gt;生成标签]中生成，但未存在于[物料库存日志&gt;&gt;日志明细]中的“唯一码”，即生成但未真正入库的唯一码</span></p><p><span>2.排序：按唯一码的“生成时间”倒叙</span></p>",bA="13",bB="68d13ee15c784936858c531459f828e7",bC="(文本框)",bD="<p><span>1.提示字：物料编码/物料名称/唯一码</span></p><p><span>2.支持对“物料编码”、“物料名称”、“唯一码”列的模糊查询</span></p><p><span>3.右侧含&quot;×&quot;的快捷清除按钮</span></p><p><span>4.点击【搜索】后返回查询结果</span></p>",bE="14",bF="29df389e25fb417ba66b34ea8fb61cb6",bG="补打",bH="<p><span>1.校验是否存在勾选行，否则Toast提示：请选择补打唯一码</span></p><p><span>2.按钮处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.Toast提示：操作成功</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.按钮限制点击，防止重复生成唯一码重复打印</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.当前【打印】按钮禁用2S，文本展示为&quot;打印中&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.2s后按钮释放，文本变回“打印”</span></p><p><span>3.打印处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.调用打印机；依次打印唯一码标签</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.标签尺寸：40mm*60mm</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.标签样式见图示，包含信息：唯一码对应二维码、唯一码、物料名称、物料规格、物料颜色、当前打印时间</span></p>",bI="style",bJ="baseStyle",bK="627587b6038d43cca051c114ac41ad32",bL="pageAlignment",bM="center",bN="fill",bO="fillType",bP="solid",bQ="color",bR=0xFFFFFFFF,bS="image",bT="imageAlignment",bU="near",bV="imageRepeat",bW="auto",bX="favicon",bY="sketchFactor",bZ="0",ca="colorStyle",cb="appliedColor",cc="fontName",cd="Applied Font",ce="borderWidth",cf="borderVisibility",cg="borderFill",ch=0xFF797979,ci="cornerRadius",cj="cornerVisibility",ck="outerShadow",cl="on",cm=false,cn="offsetX",co=5,cp="offsetY",cq="blurRadius",cr="spread",cs="r",ct=0,cu="g",cv="b",cw="a",cx=0.349019607843137,cy="adaptiveStyles",cz="interactionMap",cA="diagram",cB="objects",cC="id",cD="0258ef630dba422f946157545751c353",cE="friendlyType",cF="顶部-1600",cG="referenceDiagramObject",cH="styleType",cI="visible",cJ=true,cK=1600,cL=890,cM="imageOverrides",cN="masterId",cO="17274bcf1e104e0881fe339074a81b64",cP="256d00accb404724aefad82d8980fa9e",cQ="动态面板",cR="dynamicPanel",cS=820,cT=186,cU="location",cV="x",cW=70,cX="y",cY=160,cZ="scrollbars",da="none",db="fitToContent",dc="propagate",dd="diagrams",de="c747f32901044cc8bbf3057e61f30949",df="State1",dg="Axure:PanelDiagram",dh="8388ed0acc2b485093c3b94a2d3130e4",di="表格",dj="parentDynamicPanel",dk="panelIndex",dl="table",dm=80,dn=1